import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String safeUserInput = sanitizeInput(userInput);
        String output = "<p>User input: " + safeUserInput + "</p>";

        PrintWriter out = response.getWriter();
        out.println(output);
    }

    private String sanitizeInput(String userInput) {
        // Perform proper input validation and sanitization to prevent XSS attacks
        // You can use libraries like OWASP Java Encoder to encode user input

        return encodeForHTML(userInput);
    }

    private String encodeForHTML(String input) {
        if (input == null) {
            return "";
        }

        return input.replaceAll("&", "&amp;")
                    .replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");

